package Static_16_03_2026;

public class Static2 {
	
	static int number;
	static String name;
	static int salary;
	
	public static void SQMMinion() {
		
		System.out.println("My number is " + number);
	}
	
	public static void VSCode() {
		
		System.out.println("My name is " + name);
	}
	
	public static void MSSQL() {
		
		System.out.println("My salary is " + salary);
	}

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		Static2.number=11;
		Static2.name="Courage";
		Static2.salary=90000;
		
		Static2.SQMMinion();
		Static2.VSCode();
		Static2.MSSQL();
		

	}

}
